	    const HINT_STORAGE_KEY = 'webstats:tpad:hint-dismissed-v1';
	    const setHintVisible = (visible) => {
	      if (!hintEl) return;
	      hintEl.hidden = !visible;
	    };
	    (() => {
	      if (!hintEl) return;
	      let dismissed = false;
	      if (canUseStorage) {
	        try { dismissed = safeText(window.localStorage.getItem(HINT_STORAGE_KEY)) === '1'; } catch (e) { dismissed = false; }
	      }
		      // En modo Táctica (vista única) el hint ocupa espacio/ruido; usa “Guía” si hace falta.
		      try {
		        if (document.body && document.body.classList.contains('tactics-mode')) dismissed = true;
		      } catch (e) { /* ignore */ }
		      // En el editor de tareas normal ya hay acciones rápidas visibles; evitamos un banner inicial redundante.
		      try {
		        if (document.body && document.body.classList.contains('task-mode-board')) dismissed = true;
		      } catch (e) { /* ignore */ }
		      setHintVisible(!dismissed);
	      hintCloseBtn?.addEventListener('click', (event) => {
	        event.preventDefault();
	        setHintVisible(false);
	        if (canUseStorage) {
	          try { window.localStorage.setItem(HINT_STORAGE_KEY, '1'); } catch (e) { /* ignore */ }
	        }
	      });
	    })();

	    // UI mode: Básico vs Avanzado.
